  const pieces = [];
  if (intro) pieces.push(intro.trim());
  pieces.push((intro ? '' : (product?.in_stock ? 'Sí, tengo ' : 'Te puedo ofrecer ')) + String(product?.product_name || 'ese equipo') + '.');

