  if (shouldAppendExactProductUrl) {
    built = appendUrl(built, String(product?.product_url || '').trim());
  }
  const followUp = buildFollowUpQuestion(product);
  if (followUp) {
    built = normalizeReplySpacing(built + ' ' + followUp);
  }
