}

if (/(bitcoin|usdt|crypto|criptomon)/i.test(replyText)) {
  validationErrors.push({
    code: 'unsupported_payment_claim',
    message: 'Se detectó una mención de crypto o medio no permitido.',
    field: 'reply_text',
  });
